const scheduleHighlight = useCallback(() => {
    const container = containerRef.current;
    if (!container) return;

    cancelHighlightJob();

    const pending = [];
    container.querySelectorAll('pre > code[class*="language-"]').forEach((codeEl) => {
      // 若首层子节点已经是 Prism token，说明这个代码块已高亮完成；只有正文
