export async function readFileContent(path) {
  if (isSafUri(path)) {
    try {
      const { content, encoding, lineEnding, size } = await safReadFileText(path);
      const fileName = safDisplayName(path);
      return {
        success: true,
        message: 'File read successfully',
        content,
        file_path: path,
        file_name: fileName,
        encoding,
        line_ending: lineEnding,
        size,
      };
    } catch (e) {
      return {
        success: false,
        message: `Failed to read file: ${e?.message || e}`,
      };
    }
  }
  return invoke('read_file_content', { path });
}

async fn read_file_content(path: String) -> Result<FileOperationResult, String> {
    match fs::read(&path) {
        Ok(bytes) => {
            let encoding = detect_file_encoding(&bytes);
            let (content, _, _) = encoding.decode(&bytes);
            let content_str = content.to_string();
            let line_ending = detect_line_ending(&content_str);

            Ok(FileOperationResult {
                success: true,
                message: "File read successfully".to_string(),
                content: Some(content_str),
                file_path: Some(path),
                file_name: None,
                encoding: Some(encoding.name().to_string()),
                line_ending: Some(line_ending),
            })
        }
        Err(e) => Ok(FileOperationResult {
            success: false,
            message: format!("Failed to read file: {}", e),
            content: None,
            file_path: None,
            file_name: None,
            encoding: None,
            line_ending: None,
        }),
    }
}

const commitRename = useCallback(async (tab) => {
    const trimmed = renameValue.trim();
    setRenamingTabId(null);
    if (!trimmed || trimmed === tab.name) return;

    if (!tab.path) {
      // 未落盘标签仅修改显示名，真正保存路径交由后续系统对话框决定。
      renameTab(tab.id, trimmed);
      return;
    }

    // 已落盘文件需要同时完成磁盘重命名、编辑器状态与同步映射更新。
    const sep = tab.path.includes('\\') ? '\\' : '/';
    const dir = tab.path.substring(0, tab.path.lastIndexOf(sep) + 1);
    const newPath = dir + trimmed;
    try {
      const result = await renameFile(tab.path, newPath);
      if (result?.success !== false) {
        const actualPath = result?.file_path || newPath;
        updateTabPath(tab.id, actualPath, trimmed);
        await syncEngine.rebindLocalPath(tab.path, actualPath, trimmed);
        if (currentDir) loadDirectory(currentDir);
      } else {
        notify('error', t('notification.renameFailed'), result?.message || '');
      }
    } catch (err) {
      notify('error', t('notification.renameFailed'), String(err));
    }
  }, [renameValue, renameTab, updateTabPath, notify, t, currentDir, loadDirectory]);

export async function renameFile(oldPath, newPath) {
  if (isSafUri(oldPath)) {
    // `newPath` 可能是同级子 URI，也可能只是新文件名；SAF 只支持原地改名，
    // 不支持像本地文件系统那样跨目录 move。
    try {
      // 若调用方传入的是完整路径，只提取最终展示名交给 SAF。
      const newName = isSafUri(newPath)
        ? safDisplayName(newPath)
        : (newPath.split(/[\\/]/).pop() || newPath);
      const resultUri = await safRenameUriTo(oldPath, newName);
      return {
        success: true,
        message: 'File renamed successfully',
        file_path: resultUri || oldPath,
        file_name: newName,
      };
    } catch (e) {
      return {
        success: false,
        message: `Failed to rename file: ${e?.message || e}`,
      };
    }
  }
  return invoke('rename_file', { oldPath, newPath });
}

