export async function deleteFile(path) {
  if (isSafUri(path)) {
    const ok = await safDeleteUri(path);
    return {
      success: ok,
      message: ok ? 'Deleted successfully' : 'Failed to delete',
      file_path: ok ? path : undefined,
    };
  }
  return invoke('delete_file', { path });
}

async fn delete_file(path: String) -> Result<FileOperationResult, String> {
    let file_path = Path::new(&path);
    if !file_path.exists() {
        return Ok(FileOperationResult {
            success: false,
            message: "File does not exist".to_string(),
            content: None,
            file_path: None,
            file_name: None,
            encoding: None,
            line_ending: None,
        });
    }

    let result = if file_path.is_dir() {
        fs::remove_dir_all(&path)
    } else {
        fs::remove_file(&path)
    };

    match result {
        Ok(_) => Ok(FileOperationResult {
            success: true,
            message: "Deleted successfully".to_string(),
            content: None,
            file_path: Some(path),
            file_name: None,
            encoding: None,
            line_ending: None,
        }),
        Err(e) => Ok(FileOperationResult {
            success: false,
            message: format!("Failed to delete: {}", e),
            content: None,
            file_path: None,
            file_name: None,
            encoding: None,
            line_ending: None,
        }),
    }
}

