export async function startFileWatching(filePath) {
  // SAF 文档没有可直接接入 inotify 的真实路径；若改用轮询 `statUri` 成本较高，
  // 且 Android 上文件在编辑器外部被同时修改的场景较少，因此直接跳过监听。
  if (isSafUri(filePath)) return false;
  return invoke('start_file_watching', { filePath });
}

async fn start_file_watching(app_handle: AppHandle, file_path: String) -> Result<bool, String> {
    let path = Path::new(&file_path);
    if !path.exists() {
        return Err("File does not exist".to_string());
    }
    let app_handle_clone = app_handle.clone();
    let file_path_clone = file_path.clone();

    let initial_modified = match fs::metadata(&file_path) {
        Ok(metadata) => metadata
            .modified()
            .map(|time| {
                time.duration_since(UNIX_EPOCH)
                    .unwrap_or_default()
                    .as_secs()
            })
            .unwrap_or(0),
        Err(_) => 0,
    };

    let mut watcher = match notify::recommended_watcher(move |res: Result<Event, notify::Error>| {
        if let Ok(event) = res {
            if let EventKind::Modify(_) = event.kind {
                for path in event.paths {
                    if path.to_string_lossy() == file_path_clone {
                        let timestamp = SystemTime::now()
                            .duration_since(UNIX_EPOCH)
                            .unwrap_or_default()
                            .as_secs();

                        // Compare the last observed modified time so duplicate
                        // notify events do not fan out into repeated UI updates.
                        let should_emit = {
                            let mut state = FILE_WATCHER_STATE.lock().unwrap();
                            if let Some(last_modified) =
                                state.watched_files.get_mut(&file_path_clone)
                            {
                                if let Ok(metadata) = fs::metadata(&path) {
                                    if let Ok(modified_time) = metadata.modified() {
                                        let current_modified = modified_time
                                            .duration_since(UNIX_EPOCH)
                                            .unwrap_or_default()
                                            .as_secs();
                                        if current_modified != *last_modified {
                                            *last_modified = current_modified;
                                            true
                                        } else {
                                            false
                                        }
                                    } else {
                                        true
                                    }
                                } else {
                                    true
                                }
                            } else {
                                true
                            }
                        };

